import React, { Suspense, lazy, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, Link, Navigate, useLocation, useParams, useSearchParams } from 'react-router-dom';
import { AssetProvider } from './context/AssetContext';
import { fetchUniverse } from './services/universeService';
import PrivacyPolicy from './pages/PrivacyPolicy';
import TermsOfService from './pages/TermsOfService';
import {
  VerifyEmailPage,
  ResetPasswordPage,
  GlobalSearchPage,
  DiscoveryPage,
  CalendarPage,
  NewsPage,
  InvestorWatchlistsPage,
  TraderWatchlistsPage,
  PortfolioPage,
  AlertsPage,
  ReportsExportPage,
  SettingsPage,
  HelpSupportPage,
  InvestorFilingsPage,
} from './pages/ContractPages';
import InvestorAdvancedCharts from './pages/InvestorAdvancedCharts';
import TraderHelpSupportPage from './pages/support/HelpSupportPage';

const Home = lazy(() => import('./pages/Home'));
const Dashboard = lazy(() => import('./pages/Dashboard'));
const Login = lazy(() => import('./pages/Login'));
const Register = lazy(() => import('./pages/Register'));
const ForgotPassword = lazy(() => import('./pages/ForgotPassword'));
const ResetPassword = lazy(() => import('./pages/ResetPassword'));
const TraderStockPage = lazy(() => import('./pages/TraderStockPage'));
const TradeTerminalPage = lazy(() => import('./pages/TradeTerminalPage'));
const MinimalChartPage = lazy(() => import('./pages/MinimalChartPage'));
const TraderSettingsPage = lazy(() => import('./pages/settings/SettingsPage'));
const AdminDashboard = lazy(() => import('./components/AdminDashboard'));
const RealtimeDemoPage = lazy(() => import('./pages/RealtimeDemoPage'));
const SpecShowcasePage = lazy(() => import('./pages/SpecShowcase'));
const Onboarding = lazy(() => import('./pages/Onboarding'));

const MarketResearchDashboard = lazy(() => import('./pages/MarketResearchDashboard'));
const ScreenerPage = lazy(() => import('./pages/ScreenerPage'));

// InvestorStockPage has been removed — stocks now open in Advanced Charts

const AppLoader = () => (
  <div className="min-h-screen flex items-center justify-center bg-[#020617] text-[#E2E8F0]">
    <div className="text-center">
      <div className="mx-auto mb-4 h-10 w-10 rounded-full border-2 border-[#00f3ff]/30 border-t-[#00f3ff] animate-spin" />
      <p className="text-sm font-semibold tracking-wide">Loading RADAR...</p>
    </div>
  </div>
);

const ScrollToTop = () => {
  const location = useLocation();

  useEffect(() => {
    window.scrollTo({ top: 0, left: 0, behavior: 'auto' });
  }, [location.pathname, location.search, location.hash]);

  return null;
};

const RouteStatusPage = ({ title, message, actionTo = '/', actionLabel = 'Go Home' }) => (
  <div className="min-h-screen flex items-center justify-center bg-[#020617] text-[#E2E8F0] px-4">
    <div className="w-full max-w-lg rounded-2xl border border-white/10 bg-white/5 p-8 text-center">
      <h1 className="text-3xl font-black tracking-tight mb-3">{title}</h1>
      <p className="text-sm text-[#cbd5e1] mb-6">{message}</p>
      <Link
        to={actionTo}
        className="inline-flex items-center justify-center rounded-xl bg-[#00f3ff] text-[#0f172a] px-5 py-2.5 font-bold text-sm"
      >
        {actionLabel}
      </Link>
    </div>
  </div>
);

const DashboardAliasRoute = ({ mode }) => {
  // Set localStorage immediately so Dashboard initializer picks it up
  if (typeof window !== 'undefined' && mode) {
    localStorage.setItem('mode', mode);
  }
  // key={mode} forces full remount when switching between trader/investor
  // This resets all useState initializers so isTraderMode is derived fresh from localStorage
  return <Dashboard key={mode} />;
};

const AssetAliasRoute = () => {
  const { symbol } = useParams();
  const nextSymbol = encodeURIComponent(String(symbol || '').trim());
  return <Navigate to={`/stocks/${nextSymbol}`} replace />;
};

// Investor stock pages → redirect to Advanced Charts with symbol
const InvestorStockRedirect = () => {
  const { symbol } = useParams();
  const clean = encodeURIComponent(String(symbol || 'RELIANCE').trim().toUpperCase().replace(/\.(NS|BO)$/i, ''));
  return <Navigate to={`/investor/advanced-charts?symbol=${clean}`} replace />;
};

const OAuthCallbackRoute = () => {
  const location = useLocation();

  useEffect(() => {
    const searchParams = new URLSearchParams(location.search);
    const hashParams = new URLSearchParams(location.hash.replace(/^#/, ''));

    const token = searchParams.get('token')
      || searchParams.get('access_token')
      || hashParams.get('token')
      || hashParams.get('access_token');

    const mode = searchParams.get('mode') || hashParams.get('mode');

    if (token) {
      localStorage.setItem('token', token);
    }

    if (mode) {
      localStorage.setItem('mode', String(mode).toUpperCase() === 'TRADER' ? 'TRADER' : 'INVESTOR');
    }

    window.location.replace(token ? '/dashboard' : '/login');
  }, [location.hash, location.search]);

  return <AppLoader />;
};

const getStoredMode = () => {
  if (typeof window === 'undefined') {
    return 'INVESTOR';
  }

  return String(localStorage.getItem('mode') || 'INVESTOR').toUpperCase() === 'TRADER'
    ? 'TRADER'
    : 'INVESTOR';
};

const ProfileRoute = () => (
  getStoredMode() === 'TRADER'
    ? <Navigate to="/trader/dashboard/profile" replace />
    : <Navigate to="/investor/dashboard/profile" replace />
);

const SettingsRoute = () => (getStoredMode() === 'TRADER' ? <TraderSettingsPage /> : <SettingsPage />);

const SupportRoute = () => (getStoredMode() === 'TRADER' ? <Navigate to="/trader/dashboard/support" replace /> : <HelpSupportPage dashboardPath="/investor/dashboard" />);
const InvestorSupportRoute = () => <HelpSupportPage dashboardPath="/investor/dashboard" />;
const TraderSupportRoute = () => <TraderHelpSupportPage />;

const AdvancedChartsRoute = () => {
  const [searchParams] = useSearchParams();
  const mode = getStoredMode();

  if (mode === 'TRADER') {
    const symbol = String(searchParams.get('symbol') || 'RELIANCE').trim().toUpperCase();
    return <Navigate to={`/chart/${encodeURIComponent(symbol)}`} replace />;
  }

  return <InvestorAdvancedCharts />;
};

const DashboardRedirect = () => {
  const mode = getStoredMode();
  return <Navigate to={mode === 'TRADER' ? '/trader/dashboard' : '/investor/dashboard'} replace />;
};

class GlobalErrorBoundary extends React.Component {
  constructor(props) {
    super(props);
    this.state = { hasError: false, error: null };
  }
  static getDerivedStateFromError(error) {
    return { hasError: true, error };
  }
  componentDidCatch(error, errorInfo) {
    console.error('Global Error Boundary caught:', error, errorInfo);
  }
  render() {
    if (this.state.hasError) {
      return (
        <div className="min-h-screen flex items-center justify-center bg-[#020617] text-white p-4">
          <div className="bg-red-500/10 border border-red-500/30 p-6 rounded-xl max-w-xl text-center">
            <h2 className="text-2xl font-bold text-red-400 mb-4">Something went wrong</h2>
            <p className="text-gray-300 text-sm mb-4">
              {this.state.error && this.state.error.toString()}
            </p>
            <pre className="text-left text-xs text-red-300 bg-black/50 p-4 rounded overflow-auto mb-4 max-h-40">
              {this.state.error && this.state.error.stack}
            </pre>
            <button onClick={() => window.location.reload()} className="bg-red-500 hover:bg-red-600 text-white px-6 py-2 rounded-lg font-bold">
              Hard Refresh Page
            </button>
          </div>
        </div>
      );
    }
    return this.props.children;
  }
}

function App() {
  // Initialize market universe on app startup
  useEffect(() => {
    fetchUniverse().catch(err => console.error('Failed to initialize universe:', err));
  }, []);

  return (
    <AssetProvider>
      <GlobalErrorBoundary>
        <Router>
          <ScrollToTop />
          <Suspense fallback={<AppLoader />}>
          <Routes>
            <Route path="/" element={<Home />} />
            <Route path="/dashboard" element={<DashboardRedirect />} />
            <Route path="/dashboard/trader" element={<Navigate to="/trader/dashboard" replace />} />
            <Route path="/dashboard/investor" element={<Navigate to="/investor/dashboard" replace />} />
            <Route path="/login" element={<Login />} />
            <Route path="/register" element={<Register />} />
            <Route path="/privacy" element={<PrivacyPolicy />} />
            <Route path="/terms" element={<TermsOfService />} />
            <Route path="/verify-email" element={<VerifyEmailPage />} />
            <Route path="/forgot-password" element={<ForgotPassword />} />
            <Route path="/reset-password/:token" element={<ResetPassword />} />
            <Route path="/auth/oauth/callback" element={<OAuthCallbackRoute />} />
            <Route path="/stocks/:symbol" element={<TraderStockPage />} />
            <Route path="/trade/:symbol" element={<TradeTerminalPage />} />
            <Route path="/chart/:symbol" element={<MinimalChartPage />} />
            <Route path="/investor-stock/:symbol" element={<InvestorStockRedirect />} />
            <Route path="/asset/:symbol" element={<AssetAliasRoute />} />

            {/* Persona Dashboards */}
            <Route path="/investor/dashboard/:module?" element={<DashboardAliasRoute mode="INVESTOR" />} />
            <Route path="/trader/dashboard/:module?" element={<DashboardAliasRoute mode="TRADER" />} />

            {/* Investor Specialized Routes */}
            <Route path="/investor/momentum" element={<DashboardAliasRoute mode="INVESTOR" />} />
            <Route path="/investor/valuation" element={<DashboardAliasRoute mode="INVESTOR" />} />
            <Route path="/investor/filings" element={<InvestorFilingsPage />} />
            <Route path="/investor/screener" element={<ScreenerPage />} />
            <Route path="/investor/search" element={<GlobalSearchPage />} />
            <Route path="/investor/discovery" element={<DiscoveryPage />} />
            <Route path="/investor/calendar" element={<CalendarPage />} />
            <Route path="/investor/news" element={<NewsPage />} />
            <Route path="/investor/watchlists" element={<InvestorWatchlistsPage />} />
            <Route path="/investor/portfolio" element={<PortfolioPage />} />
            <Route path="/investor/alerts" element={<AlertsPage />} />
            <Route path="/investor/reports/export" element={<ReportsExportPage />} />
            <Route path="/investor/profile" element={<Navigate to="/investor/dashboard/profile" replace />} />
            <Route path="/investor/settings" element={<SettingsPage />} />
            <Route path="/investor/support" element={<HelpSupportPage dashboardPath="/investor/dashboard" />} />
            <Route path="/investor/advanced-charts" element={<InvestorAdvancedCharts />} />

            {/* Trader Specialized Routes */}
            <Route path="/trader/profile" element={<Navigate to="/trader/dashboard/profile" replace />} />
            <Route path="/trader/settings" element={<Navigate to="/trader/dashboard/settings" replace />} />
            <Route path="/trader/support" element={<Navigate to="/trader/dashboard/support" replace />} />
            <Route path="/trader/terminal/:symbol" element={<TradeTerminalPage />} />
            <Route path="/trader/charts/:symbol" element={<MinimalChartPage />} />
            <Route path="/trader/watchlists" element={<TraderWatchlistsPage />} />

            {/* Legacy/Redirect Routes */}
            <Route path="/profile" element={<ProfileRoute />} />
            <Route path="/settings" element={<SettingsRoute />} />
            <Route path="/support" element={<SupportRoute />} />
            <Route path="/help" element={<SupportRoute />} />
            <Route path="/advanced-charts" element={<AdvancedChartsRoute />} />

            {/* Legacy Investor Mappings (Redirect to namespaced) */}
            <Route path="/screener" element={<Navigate to="/investor/screener" replace />} />
            <Route path="/search" element={<Navigate to="/investor/search" replace />} />
            <Route path="/discovery" element={<Navigate to="/investor/discovery" replace />} />
            <Route path="/calendar" element={<Navigate to="/investor/calendar" replace />} />
            <Route path="/news" element={<Navigate to="/investor/news" replace />} />
            <Route path="/watchlists" element={<Navigate to="/investor/watchlists" replace />} />
            <Route path="/portfolio" element={<Navigate to="/investor/portfolio" replace />} />
            <Route path="/alerts" element={<Navigate to="/investor/alerts" replace />} />
            <Route path="/reports/export" element={<Navigate to="/investor/reports/export" replace />} />
            <Route path="/trader-profile" element={<Navigate to="/trader/dashboard/profile" replace />} />
            <Route path="/admin" element={<AdminDashboard />} />
            <Route path="/admin/health" element={<Navigate to="/admin" replace />} />
            <Route path="/demo" element={<RealtimeDemoPage />} />
            <Route path="/research-dashboard" element={<MarketResearchDashboard />} />
            <Route path="/spec/components" element={<SpecShowcasePage />} />
            <Route path="/onboarding" element={<Onboarding />} />
            <Route path="/404" element={<RouteStatusPage title="404 - Not Found" message="The page you requested does not exist or may have moved." actionTo="/" actionLabel="Return Home" />} />
            <Route path="/500" element={<RouteStatusPage title="500 - Server Error" message="Something went wrong while processing your request. Please try again." actionTo="/" actionLabel="Return Home" />} />
            <Route path="*" element={<Navigate to="/404" replace />} />
          </Routes>
        </Suspense>
      </Router>
      </GlobalErrorBoundary>
    </AssetProvider>
  );
}

export default App;

import axios from 'axios';

const apiBaseUrl = import.meta.env.VITE_API_BASE_URL || '/api';
const STOCK_SUFFIX_REGEX = /\b([A-Z0-9^_-]+)\.(NS|BO)\b/g;

const stripStockSuffixInString = (value) => String(value || '').replace(STOCK_SUFFIX_REGEX, '$1');

const sanitizeStockSuffixes = (value) => {
    if (Array.isArray(value)) {
        return value.map((item) => sanitizeStockSuffixes(item));
    }

    if (value && typeof value === 'object') {
        return Object.entries(value).reduce((acc, [key, item]) => {
            acc[key] = sanitizeStockSuffixes(item);
            return acc;
        }, {});
    }

    if (typeof value === 'string') {
        return stripStockSuffixInString(value);
    }

    return value;
};

export const hasAuthToken = () => {
    if (typeof window === 'undefined') {
        return false;
    }

    return Boolean(localStorage.getItem('token'));
};

export const isUnauthorizedError = (error) => error?.response?.status === 401;

const api = axios.create({
    baseURL: apiBaseUrl,
});

api.interceptors.request.use((config) => {
    const token = localStorage.getItem('token');
    if (token) {
        config.headers.Authorization = `Bearer ${token}`;
    }
    return config;
}, (error) => {
    return Promise.reject(error);
});

const AUTH_KEYS = ['token', 'user', 'mode', 'userId', 'userEmail'];

const clearAuthAndRedirect = () => {
    AUTH_KEYS.forEach(k => localStorage.removeItem(k));
    // Only redirect if not already on an auth page
    if (typeof window !== 'undefined') {
        const publicPaths = ['/login', '/register', '/forgot-password', '/reset-password'];
        const isPublicPath = publicPaths.some(p => window.location.pathname.startsWith(p));
        if (!isPublicPath) {
            window.location.href = '/login';
        }
    }
};

api.interceptors.response.use(
    (response) => {
        if (response && typeof response === 'object' && response.data !== undefined) {
            //response.data = sanitizeStockSuffixes(response.data);
        }
        return response;
    },
    (error) => {
        const status = error.response?.status;
        const msg = error.response?.data?.error || '';
        const requestAuthHeader = error.config?.headers?.Authorization || error.config?.headers?.authorization || error.config?.headers?.['x-auth-token'];

        // Only force a re-login when the failing request actually carried auth credentials.
        // This avoids bouncing public route navigation back to /login because of optional background fetches.
        if (status === 401) {
            if (requestAuthHeader) {
                clearAuthAndRedirect();
            }
            return Promise.reject(error);
        }

        // Dispatch api-error event for non-auth errors only (avoids spurious error popups on 401)
        if (typeof window !== 'undefined' && msg && status !== 401) {
            const event = new CustomEvent('api-error', { detail: { message: msg } });
            window.dispatchEvent(event);
        }
        return Promise.reject(error);
    }
);

export const toggleWatchlist = async (symbol, mode) => {
    try {
        const params = mode ? { mode } : {};
        const watchlistsRes = await api.get('/watchlist', { params });
        let watchlists = watchlistsRes.data?.data || watchlistsRes.data || [];

        let defaultId = null;
        if (!watchlists || watchlists.length === 0) {
            const createRes = await api.post('/watchlist', { name: mode === 'investor' ? 'Investor Portfolio' : 'Trader Watchlist', mode });
            defaultId = createRes.data?._id;
            watchlists = [createRes.data];
        } else {
            defaultId = watchlists[0]._id;
        }

        const isWatched = (watchlists[0].items || []).some(
            i => String(i.symbol || i).replace(/\.(NS|BO)$/i, '') === String(symbol).replace(/\.(NS|BO)$/i, '')
        );

        if (isWatched) {
            const removeRes = await api.delete(`/watchlist/${defaultId}/remove/${encodeURIComponent(symbol)}`);
            return { action: 'removed', watchlist: removeRes.data };
        } else {
            const addRes = await api.post(`/watchlist/${defaultId}/add`, { symbol });
            return { action: 'added', watchlist: addRes.data };
        }
    } catch (error) {
        console.error('Watchlist toggle failed:', error);
        throw error;
    }
};

export const saveToDefaultWatchlist = async (symbol) => toggleWatchlist(symbol, 'investor');

export default api;

import { fetchOHLCData, fetchOHLCForChart, fetchPriceHistory, hasOHLCData } from './ohlcApi';
import { fetchMarketHistory } from './marketApi';




export const fetchEnhancedMarketHistory = async (
    symbol,
    type = 'STOCK',
    interval = '1D',
    options = {}
) => {
    try {
        if (type === 'STOCK') {
            const timeframeMap = {
                '1D': '1d',
                '1H': '1h',
                '15M': '15m',
                '5M': '5m',
                '1M': '1m',
            };

            const timeframe = timeframeMap[interval] || '1d';

            console.log(`[Enhanced] Attempting OHLC fetch for ${symbol} (${timeframe})`);

            const ohlcResult = await fetchOHLCData(symbol, {
                exchange: 'NSE',
                timeframe,
                limit: options.limit || 365,
                ...options,
            });

            if (ohlcResult.data && ohlcResult.data.length > 0) {
                console.log(`[Enhanced] âœ… Using OHLC data (${ohlcResult.count} records)`);

                const formattedData = ohlcResult.data.map(candle => ({
                    timestamp: candle.timestamp,
                    open: candle.open,
                    high: candle.high,
                    low: candle.low,
                    close: candle.close,
                    volume: candle.volume || 0,
                }));

                return {
                    data: formattedData,
                    indicators: null, // Can add technical indicators here later
                    source: 'ohlc-storage',
                    cached: true,
                };
            }

            console.log(`[Enhanced] âš ï¸ No OHLC data found, falling back to external API`);
        }

        console.log(`[Enhanced] Using external API for ${symbol}`);
        const result = await fetchMarketHistory(symbol, type, interval);

        return {
            ...result,
            source: 'external-api',
            cached: false,
        };
    } catch (error) {
        console.error('[Enhanced] Error fetching market history:', error);

        try {
            console.log(`[Enhanced] Attempting fallback to external API`);
            const fallbackResult = await fetchMarketHistory(symbol, type, interval);
            return {
                ...fallbackResult,
                source: 'external-api-fallback',
                cached: false,
            };
        } catch (fallbackError) {
            console.error('[Enhanced] Fallback also failed:', fallbackError);
            throw fallbackError;
        }
    }
};


export const fetchEnhancedChartData = async (symbol, options = {}) => {
    const {
        type = 'STOCK',
        interval = '1D',
        limit = 90,
    } = options;

    try {
        if (type === 'STOCK') {
            const timeframeMap = {
                '1D': '1d',
                '1H': '1h',
                '15M': '15m',
                '5M': '5m',
            };

            const timeframe = timeframeMap[interval] || '1d';

            const chartData = await fetchOHLCForChart(symbol, {
                exchange: 'NSE',
                timeframe,
                limit,
            });

            if (chartData && chartData.length > 0) {
                console.log(`[Chart] âœ… Using OHLC storage (${chartData.length} points)`);
                return chartData;
            }
        }

        console.log(`[Chart] Using external API for ${symbol}`);
        const result = await fetchMarketHistory(symbol, type, interval);

        return result.data || [];
    } catch (error) {
        console.error('[Chart] Error fetching chart data:', error);
        return [];
    }
};


export const fetchSimplePriceHistory = async (symbol, days = 30) => {
    try {
        const priceHistory = await fetchPriceHistory(symbol, {
            exchange: 'NSE',
            timeframe: '1d',
            limit: days,
        });

        if (priceHistory && priceHistory.length > 0) {
            console.log(`[Price] âœ… Using OHLC storage (${priceHistory.length} days)`);
            return priceHistory;
        }

        console.log(`[Price] Using external API`);
        const result = await fetchMarketHistory(symbol, 'STOCK', '1D');

        if (!result.data) return [];

        return result.data.slice(-days).map(candle => ({
            timestamp: candle.timestamp,
            price: candle.close,
            date: new Date(candle.timestamp).toLocaleDateString(),
        }));
    } catch (error) {
        console.error('[Price] Error fetching price history:', error);
        return [];
    }
};


export const hasCachedData = async (symbol) => {
    try {
        return await hasOHLCData(symbol, 'NSE');
    } catch (error) {
        return false;
    }
};


export const getDataFreshness = async (symbol) => {
    try {
        const hasCached = await hasCachedData(symbol);

        if (!hasCached) {
            return {
                cached: false,
                message: 'Using real-time external API',
            };
        }

        const latestResult = await fetchOHLCData(symbol, {
            exchange: 'NSE',
            timeframe: '1d',
            limit: 1,
        });

        if (latestResult.data && latestResult.data.length > 0) {
            const latestTimestamp = new Date(latestResult.data[0].timestamp);
            const now = new Date();
            const hoursDiff = (now - latestTimestamp) / (1000 * 60 * 60);

            return {
                cached: true,
                latestDate: latestTimestamp.toLocaleDateString(),
                hoursOld: Math.round(hoursDiff),
                message: hoursDiff < 24 
                    ? 'Data is current (less than 24 hours old)'
                    : `Data is ${Math.round(hoursDiff / 24)} days old`,
            };
        }

        return {
            cached: true,
            message: 'Cached data available',
        };
    } catch (error) {
        return {
            cached: false,
            error: error.message,
        };
    }
};

export default {
    fetchEnhancedMarketHistory,
    fetchEnhancedChartData,
    fetchSimplePriceHistory,
    hasCachedData,
    getDataFreshness,
};

import api from './api';

// Returns the localStorage key scoped by mode so trader/investor progress is separate
export const getProgressKey = (courseId, mode = '') => {
    const prefix = mode ? `${mode}_` : '';
    return `radar_academy_progress_${prefix}${courseId}`;
};

export const fetchCourses = async (audience = '') => {
    try {
        const url = audience ? `/learning?audience=${audience}` : '/learning';
        const res = await api.get(url);
        return Array.isArray(res.data?.data) ? res.data.data : Array.isArray(res.data) ? res.data : [];
    } catch (err) {
        console.error('Failed to fetch courses:', err);
        return [];
    }
};

export const fetchCourse = async (id) => {
    try {
        const res = await api.get(`/learning/${id}`);
        return res.data?.data ?? res.data ?? null;
    } catch (err) {
        console.error(`Failed to fetch course ${id}:`, err);
        return null;
    }
};

export const saveProgress = async (courseId, chapterId, completed = true) => {
    try {
        const userId = localStorage.getItem('userId') || 'anonymous';
        await api.post('/learning/progress', { courseId, chapterId, completed, userId });
    } catch (err) {
        // silently fail — progress is also tracked locally
    }
};

export const submitQuiz = async (courseId, answers) => {
    try {
        const userId = localStorage.getItem('userId') || 'anonymous';
        const res = await api.post('/learning/quiz', { courseId, answers, userId });
        return res.data?.data ?? null;
    } catch (err) {
        console.error('Failed to submit quiz:', err);
        return null;
    }
};

import { useState } from 'react';
import { useSystemStatus, useProviderHealth } from '../hooks/useAdminStatus';
import { useQuoteStats, useRateLimits } from '../hooks/useRealtimeQuote';
import {
    triggerManualUpdate,
