                                    {/* Interface Toggle Section */}
                                    <div className="px-6 py-6 bg-[#F8FAFC]">
                                        <p className="text-[10px] font-black text-[#94A3B8] uppercase tracking-[0.1em] text-center mb-4">
                                            CHOOSE YOUR INTERFACE
