                            </div>
                          </div>
                          <span className="text-xs font-normal text-slate-400">Industry: {industry}</span>
                        </div>
                        <div className="peer-comp-table">
                          <div className="pct-header">
                            <span>Metric</span><span>Company</span><span>Industry Avg</span>
