          setLivePrice(event.price);
          setLastUpdate(new Date().toLocaleTimeString());
        }
        if (event.change !== null && event.change !== undefined) {
          setLiveChange({ val: (event.price * (event.change / 100)).toFixed(2), pct: event.change });
        }
      }
    });

    return () => {
