            else if (timeFilter === '1W') interval = '1h';
            else if (timeFilter === '1M') interval = '1D';
            else if (timeFilter === '3M') interval = '1D';
            else if (timeFilter === '6M') interval = '1W';
            else if (timeFilter === '1Y') interval = '1W';
            else if (timeFilter === '5Y') interval = '1M';
