                                        <stop offset="5%" stopColor={stock.isPositive ? '#3E84F6' : '#e11d48'} stopOpacity={0.3} />
                                        <stop offset="95%" stopColor={stock.isPositive ? '#3E84F6' : '#e11d48'} stopOpacity={0} />
                                    </linearGradient>
                                </defs>
                                <Area
                                    type="monotone"
                                    dataKey="value"
                                    stroke={stock.isPositive ? '#3E84F6' : '#e11d48'}
                                    strokeWidth={3}
