      { id: '8grid', label: '8 Panel',    count: 8, svg: [[0,0,0.5,1],[0.5,0,1,1],[1,0,1.5,1],[1.5,0,2,1],[0,1,0.5,2],[0.5,1,1,2],[1,1,1.5,2],[1.5,1,2,2]] },
