                                        <span className="text-[#f0f6fc]">{activeFilters[f.id] || 'Any'}</span>
                                        <ChevronDown size={14} className={`transition-transform duration-300 ${openFilter === f.id ? 'rotate-180' : ''}`} />
                                    </div>

                                    {openFilter === f.id && (
