    if (!rows.length) {
      return [];
    }

    const multiplier = 2 / (20 + 1);
    let previous = rows[0].close;

    return rows.map((row) => {
      previous = (row.close - previous) * multiplier + previous;
      return { time: row.time, value: Number(previous.toFixed(2)) };
    });
  }, [rows]);

