    const resizeObserver = new ResizeObserver(() => {
      if (mainRef.current && mainChart) {
        mainChart.applyOptions({ width: mainRef.current.clientWidth, height: 360 });
        performFit();
      }
    });
    resizeObserver.observe(mainRef.current);

    // Initial fit
    performFit();

    return () => {
      resizeObserver.disconnect();
      destroySimpleChart();
    };
