              </SectionPanel>

              <SectionPanel title="Live Signal Feed" subtitle="Real-time market intelligence from scan" accent="violet">
                <div className="max-h-[260px] space-y-2 overflow-y-auto pr-1">
                  {filteredStocks.slice(0, 8).map((s, index) => (
                    <motion.div
